const fileName = $input.first().json.name || '';
const match = fileName.match(/^(\d{13})_text\.(pdf|png)$/i);

if (match) {
  return [{
    json: {
      ...$input.first().json,
      isbn: match[1],
      extension: match[2].toLowerCase(),
      isValid: true,
      driveFileId: $input.first().json.id,
      driveUrl: $input.first().json.webViewLink || $input.first().json.webContentLink || '',
      mimeType: $input.first().json.mimeType || ''
    }
  }];
} else {
  return [{
    json: {
      ...$input.first().json,
      isbn: null,
      extension: null,
      isValid: false,
      driveFileId: $input.first().json.id,
      driveUrl: '',
      mimeType: ''
    }
  }];
}

const items = $input.all();
const prevData = $('Validate Filename').first().json;
const isbn = prevData.isbn;
const driveFileId = prevData.driveFileId;
const driveUrl = prevData.driveUrl;
const extension = prevData.extension;

let authorName = 'Author';
let authorEmail = '';
let revisionNumber = 1;
let airtableRecordId = null;
let isUpdate = false;

// Check if Airtable returned a record
if (items.length > 0 && items[0].json && items[0].json.id) {
  const rec = items[0].json;
  const fields = rec.fields || rec;
  authorName = fields['Author name'] || 'Author';
  authorEmail = fields['Author email'] || '';
  revisionNumber = (parseInt(fields['Revision number']) || 0) + 1;
  airtableRecordId = rec.id;
  isUpdate = true;
}

return [{
  json: {
    isbn,
    driveFileId,
    driveUrl,
    extension,
    authorName,
    authorEmail,
    revisionNumber,
    airtableRecordId,
    isUpdate
  }
}];

const prevMeta = $('Analyze image').first().json;

try {
  const raw = $input.first().json;
  let text = '';

  // Handle multiple possible response structures
  // Structure 1: simplified output (content array at top level)
  if (raw.content && Array.isArray(raw.content)) {
    text = raw.content
      .filter(c => c.type === 'text' || c.type === 'output_text')
      .map(c => c.text)
      .join('');
  }
  // Structure 2: unsimplified OpenAI output (output array)
  if (!text && raw.output && Array.isArray(raw.output)) {
    for (const item of raw.output) {
      if (item.content && Array.isArray(item.content)) {
        text += item.content
          .filter(c => c.type === 'output_text' || c.type === 'text')
          .map(c => c.text)
          .join('');
      }
      if (typeof item.text === 'string') {
        text += item.text;
      }
    }
  }
  // Structure 3: direct text field
  if (!text && typeof raw.text === 'string') {
    text = raw.text;
  }

  // Aggressively strip markdown fences
  text = text.replace(/^[\s\S]*?```json\s*/i, '');
  text = text.replace(/\s*```[\s\S]*$/i, '');
  text = text.trim();

  if (!text) {
    throw new Error('No text content found in AI response');
  }

  const analysis = JSON.parse(text);

  return [{
    json: {
      parseError: false,
      analysis,
      isbn: prevMeta.isbn,
      driveUrl: prevMeta.driveUrl,
      authorName: prevMeta.authorName,
      authorEmail: prevMeta.authorEmail,
      revisionNumber: prevMeta.revisionNumber,
      airtableRecordId: prevMeta.airtableRecordId,
      isUpdate: prevMeta.isUpdate
    }
  }];
} catch (err) {
  return [{
    json: {
      parseError: true,
      errorMessage: err.message,
      isbn: prevMeta.isbn,
      driveUrl: prevMeta.driveUrl,
      authorName: prevMeta.authorName,
      authorEmail: prevMeta.authorEmail,
      revisionNumber: prevMeta.revisionNumber,
      airtableRecordId: prevMeta.airtableRecordId,
      isUpdate: prevMeta.isUpdate
    }
  }];
}

const item = $input.first().json;
const a = item.analysis;

// Enforce status rules
let finalStatus = a.status;
if (finalStatus !== 'PASS' && finalStatus !== 'REVIEW NEEDED') {
  finalStatus = 'REVIEW NEEDED';
}
if (a.confidence_score < 90) {
  finalStatus = 'REVIEW NEEDED';
}

const now = new Date().toISOString();

return [{
  json: {
    isbn: item.isbn,
    driveUrl: item.driveUrl,
    authorName: item.authorName,
    authorEmail: item.authorEmail,
    revisionNumber: item.revisionNumber,
    airtableRecordId: item.airtableRecordId,
    isUpdate: item.isUpdate,
    finalStatus,
    confidenceScore: a.confidence_score,
    issueType: (a.issue_type || []).join(', '),
    issueSeverity: a.issue_severity || 'none',
    detectionTimestamp: now,
    correctionInstructions: (a.correction_instructions || []).join('\n'),
    issueSummary: a.issue_summary || '',
    issueMarkers: (a.issue_markers || []).join('\n'),
    manualReviewReason: a.manual_review_reason || '',
    visualAnnotationsUrl: a.visual_annotations_url || null,
    issueMarkersArray: a.issue_markers || [],
    correctionInstructionsArray: a.correction_instructions || []
  }
}];

const airtable = $input.first().json;
const fields = airtable.fields || airtable;

const supportContact = 'support@bookleaf.com';
const resubTimeline = '5 business days';

const isbn = fields['ISBN'] || '';
const authorName = fields['Author name'] || 'Author';
const authorEmail = fields['Author email'] || 'fallback@bookleaf.com';
const status = fields['Status'] || 'REVIEW NEEDED';
const issueSummary = fields['Issue summary'] || '';
const issueMarkers = fields['Issue markers'] || '';
const correctionInstructions = fields['Correction instructions'] || '';

let subject = '';
let html = '';

if (status === 'PASS') {
  subject = `Book Cover Validation Passed – ${isbn}`;
  html = `<!DOCTYPE html><html><head><meta charset="utf-8"></head><body style="font-family:Arial,sans-serif;line-height:1.6;color:#333;padding:20px;">` +
    `<p>Hi ${authorName},</p>` +
    `<p>Thank you for submitting your book cover.</p>` +
    `<p>We have completed the automated validation, and your cover has successfully passed all required checks.</p>` +
    `<p><strong>Status: PASS</strong></p>` +
    `<p>Checks completed successfully:</p>` +
    `<ul>` +
    `<li>✅ No text overlap detected in the reserved award badge zone</li>` +
    `<li>✅ Author name placement appears compliant with the front-cover safe area</li>` +
    `<li>✅ Text spacing appears acceptable within the cover margins</li>` +
    `<li>✅ Cover quality appears clear and legible</li>` +
    `</ul>` +
    `<p>No changes are required at this stage. Your cover can now move forward in the workflow.</p>` +
    `<p>If you have any questions, please reply to this email or contact ${supportContact}.</p>` +
    `<p>Regards,<br/>BookLeaf Publishing Team</p>` +
    `</body></html>`;
} else {
  subject = `Book Cover Review Needed – ${isbn}`;

  const markersList = issueMarkers.split(/\n/).filter(m => m.trim());
  const instructionsList = correctionInstructions.split(/\n/).filter(i => i.trim());

  const markersHtml = markersList.length > 0
    ? markersList.map(m => `<li>${m.trim()}</li>`).join('')
    : '<li>Issue detected – see summary below</li>';

  const instructionsHtml = instructionsList.length > 0
    ? instructionsList.map(i => `<li>${i.trim()}</li>`).join('')
    : '<li>Please review and correct the flagged issues</li>';

  html = `<!DOCTYPE html><html><head><meta charset="utf-8"></head><body style="font-family:Arial,sans-serif;line-height:1.6;color:#333;padding:20px;">` +
    `<p>Hi ${authorName},</p>` +
    `<p>Thank you for submitting your book cover.</p>` +
    `<p>We have completed the automated validation, and your current cover needs improvement before approval.</p>` +
    `<p><strong>Status: REVIEW NEEDED</strong></p>` +
    `<p><strong>Issues identified:</strong></p>` +
    `<ul>${markersHtml}</ul>` +
    `<p><strong>Please make the following corrections:</strong></p>` +
    `<ul>${instructionsHtml}</ul>` +
    `<p><strong>Summary:</strong><br/>${issueSummary}</p>` +
    `<p>Please resubmit the revised cover within ${resubTimeline} so we can continue processing without delay.</p>` +
    `<p>If you need any clarification, please reply to this email or contact ${supportContact}.</p>` +
    `<p>Regards,<br/>BookLeaf Publishing Team</p>` +
    `</body></html>`;
}

return [{
  json: {
    subject,
    html,
    toEmail: authorEmail
  }
}];
